{
  "datasets": [
    {
      "name": "ds_total_complaints",
      "displayName": "KPI: Total Complaints",
      "queryLines": [
        "SELECT COUNT(*) AS total_complaints FROM cvr_dev_ai_kit.cvr_tm_demo.Customer_Complaints"
      ]
    },
    {
      "name": "ds_vehicles_affected",
      "displayName": "KPI: Vehicles Affected",
      "queryLines": [
        "SELECT COUNT(DISTINCT vehicle_id) AS vehicles_affected FROM cvr_dev_ai_kit.cvr_tm_demo.Customer_Complaints"
      ]
    },
    {
      "name": "ds_avg_days",
      "displayName": "KPI: Avg Days to Complaint",
      "queryLines": [
        "SELECT CAST(ROUND(AVG(days_since_delivery), 0) AS INT) AS avg_days FROM cvr_dev_ai_kit.cvr_tm_demo.silver_complaint_correlation"
      ]
    },
    {
      "name": "ds_monthly_trend",
      "displayName": "Chart: Monthly Trend by Category",
      "queryLines": [
        "SELECT complaint_month, complaint_category, SUM(total_complaints) AS total_complaints FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_dashboard GROUP BY complaint_month, complaint_category ORDER BY complaint_month"
      ]
    },
    {
      "name": "ds_category_mix",
      "displayName": "Chart: Category Mix",
      "queryLines": [
        "SELECT complaint_category, COUNT(*) AS complaint_count FROM cvr_dev_ai_kit.cvr_tm_demo.Customer_Complaints GROUP BY complaint_category ORDER BY complaint_count DESC"
      ]
    },
    {
      "name": "ds_dealer_volume",
      "displayName": "Chart: Dealer Complaint Volume",
      "queryLines": [
        "SELECT dealer_id, SUM(total_complaints) AS total_complaints FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_dashboard GROUP BY dealer_id ORDER BY total_complaints DESC"
      ]
    },
    {
      "name": "ds_urgent_complaints",
      "displayName": "Chart: Urgent Complaints (<7 days)",
      "queryLines": [
        "SELECT complaint_category, SUM(complaints_within_7days) AS within_7days FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_dashboard GROUP BY complaint_category ORDER BY within_7days DESC"
      ]
    },
    {
      "name": "ds_high_risk_dealers",
      "displayName": "KPI: High Risk Dealers",
      "queryLines": [
        "SELECT COUNT(DISTINCT dealer_id) AS high_risk_dealers FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_dashboard WHERE dealer_risk_flag = 'High Risk Dealer'"
      ]
    },
    {
      "name": "ds_monitor_dealers",
      "displayName": "KPI: Monitor Dealers",
      "queryLines": [
        "SELECT COUNT(DISTINCT dealer_id) AS monitor_dealers FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_dashboard WHERE dealer_risk_flag = 'Monitor'"
      ]
    },
    {
      "name": "ds_avg_fail_pct",
      "displayName": "KPI: Avg Failed Inspection %",
      "queryLines": [
        "SELECT ROUND(AVG(pct_with_failed_inspection), 1) AS avg_fail_pct FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_dashboard"
      ]
    },
    {
      "name": "ds_dealer_complaints_bar",
      "displayName": "Chart: Complaints per Dealer",
      "queryLines": [
        "SELECT dealer_id, SUM(total_complaints) AS total_complaints FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_dashboard GROUP BY dealer_id ORDER BY total_complaints DESC"
      ]
    },
    {
      "name": "ds_dealer_fail_rate",
      "displayName": "Chart: Failed Inspection Rate per Dealer",
      "queryLines": [
        "SELECT dealer_id, ROUND(AVG(pct_with_failed_inspection), 1) AS avg_pct_failed FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_dashboard GROUP BY dealer_id ORDER BY avg_pct_failed DESC"
      ]
    },
    {
      "name": "ds_dealer_scorecard",
      "displayName": "Table: Dealer Scorecard",
      "queryLines": [
        "SELECT dealer_id, SUM(total_complaints) AS total_complaints, SUM(affected_vehicles) AS vehicles, ROUND(AVG(avg_days_since_delivery), 1) AS avg_days, ROUND(AVG(pct_with_failed_inspection), 1) AS pct_failed, SUM(complaints_within_7days) AS within_7days, SUM(complaints_within_30days) AS within_30days, CASE MAX(CASE WHEN dealer_risk_flag = 'High Risk Dealer' THEN 3 WHEN dealer_risk_flag = 'Monitor' THEN 2 ELSE 1 END) WHEN 3 THEN 'High Risk Dealer' WHEN 2 THEN 'Monitor' ELSE 'Normal' END AS risk_flag FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_dashboard GROUP BY dealer_id ORDER BY total_complaints DESC"
      ]
    },
    {
      "name": "ds_gap_count",
      "displayName": "KPI: Gap Count",
      "queryLines": [
        "SELECT COUNT(*) AS gap_count FROM cvr_dev_ai_kit.cvr_tm_demo.gold_epdi_gap_analysis"
      ]
    },
    {
      "name": "ds_preventable_complaints",
      "displayName": "KPI: Preventable Complaints",
      "queryLines": [
        "SELECT SUM(complaint_count) AS preventable_complaints FROM cvr_dev_ai_kit.cvr_tm_demo.gold_epdi_gap_analysis"
      ]
    },
    {
      "name": "ds_gap_vehicles",
      "displayName": "KPI: Vehicles in Gap",
