        "SELECT SUM(vehicle_count) AS gap_vehicles FROM cvr_dev_ai_kit.cvr_tm_demo.gold_epdi_gap_analysis"
      ]
    },
    {
      "name": "ds_gap_complaints_bar",
      "displayName": "Chart: Complaints per Gap Category",
      "queryLines": [
        "SELECT gap_category, complaint_count FROM cvr_dev_ai_kit.cvr_tm_demo.gold_epdi_gap_analysis ORDER BY complaint_count DESC"
      ]
    },
    {
      "name": "ds_gap_vehicles_bar",
      "displayName": "Chart: Vehicles per Gap Category",
      "queryLines": [
        "SELECT gap_category, vehicle_count FROM cvr_dev_ai_kit.cvr_tm_demo.gold_epdi_gap_analysis ORDER BY vehicle_count DESC"
      ]
    },
    {
      "name": "ds_gap_table",
      "displayName": "Table: ePDI Gap Recommendations",
      "queryLines": [
        "SELECT gap_category, complaint_count, vehicle_count, gap_duration_days, severity, action_required, recommendation FROM cvr_dev_ai_kit.cvr_tm_demo.gold_epdi_gap_analysis ORDER BY complaint_count DESC"
      ]
    },
    {
      "name": "ds_high_risk_complaints",
      "displayName": "KPI: High Risk Complaints",
      "queryLines": [
        "SELECT SUM(CASE WHEN risk_level = 'High Risk' THEN complaint_count ELSE 0 END) AS high_risk_complaints FROM cvr_dev_ai_kit.cvr_tm_demo.gold_delivery_service_link"
      ]
    },
    {
      "name": "ds_damage_at_delivery",
      "displayName": "KPI: Damage at Delivery",
      "queryLines": [
        "SELECT SUM(damage_at_delivery) AS damage_complaints FROM cvr_dev_ai_kit.cvr_tm_demo.gold_delivery_service_link"
