    {
      "name": "ds_dealer_delivery_bar",
      "displayName": "Chart: Dealer Risk by Delivery",
      "queryLines": [
        "SELECT dealer_id, risk_level, SUM(complaint_count) AS complaint_count FROM cvr_dev_ai_kit.cvr_tm_demo.gold_delivery_service_link GROUP BY dealer_id, risk_level ORDER BY dealer_id"
