    },
    {
      "name": "f3c05e29",
      "displayName": "KPI: Not Covered Complaints",
      "queryLines": [
        "SELECT COUNT(*) AS not_covered FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_detail WHERE coverage_gap LIKE 'NOT COVERED%'"
