    },
    {
      "name": "2a760fea",
      "displayName": "KPI: Delivered Despite Inspection Failure",
      "queryLines": [
        "SELECT COUNT(*) AS covered_but_delivered FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_detail WHERE coverage_gap NOT LIKE 'NOT COVERED%' AND inspection_status = 'FAIL'"
      ]
    },
    {
      "name": "253af805",
      "displayName": "KPI: Unique Sub-Issues",
      "queryLines": [
        "SELECT COUNT(DISTINCT specific_issue) AS unique_issues FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_detail WHERE specific_issue != 'Uncategorised - Review Needed'"
      ]
    },
    {
      "name": "43e50314",
      "displayName": "Chart: Complaints by Specific Issue",
      "queryLines": [
        "SELECT specific_issue, COUNT(*) AS complaints, CASE WHEN MAX(CASE WHEN coverage_gap LIKE 'NOT COVERED%' THEN 1 ELSE 0 END)=1 THEN 'Not Covered' WHEN MAX(CASE WHEN inspection_status='FAIL' THEN 1 ELSE 0 END)=1 THEN 'Inspection Failed' ELSE 'Passed Inspection' END AS coverage_status FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_detail WHERE specific_issue != 'Uncategorised - Review Needed' GROUP BY specific_issue ORDER BY complaints DESC"
      ]
    },
    {
      "name": "ee58ea93",
      "displayName": "Chart: Inspection Catch Rate by Sub-Issue",
      "queryLines": [
        "SELECT specific_issue, ROUND(COUNT(CASE WHEN inspection_status='FAIL' THEN 1 END)*100.0/COUNT(*),1) AS pct_caught FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_detail WHERE specific_issue != 'Uncategorised - Review Needed' GROUP BY specific_issue ORDER BY pct_caught DESC"
      ]
    },
    {
      "name": "c2dc361a",
      "displayName": "Table: Complaint Detail",
