        "SELECT complaint_id, vehicle_id, complaint_category, specific_issue, inspection_status, coverage_gap, dealer_id, days_since_delivery FROM cvr_dev_ai_kit.cvr_tm_demo.gold_complaint_detail ORDER BY complaint_category, specific_issue"
